   322→    private fun syncLogs() {
   323→        synchronized(OllamaService.logBuffer) { liveLogs.addAll(OllamaService.logBuffer) }
   324→        OllamaService.onLogReceived = { line ->
   325→            viewModelScope.launch(Dispatchers.Main) {
   326→                liveLogs.add(line)
   327→                if (liveLogs.size > 1000) liveLogs.removeAt(0)
   328→            }
   329→        }
   330→        // Poll llama.cpp logs and merge into liveLogs
   331→        viewModelScope.launch(Dispatchers.IO) {
   332→            var lastSize = 0
   333→            while (true) {
   334→                val lines = synchronized(LlamaService.logBuffer) {
   335→                    if (LlamaService.logBuffer.size > lastSize)
   336→                        LlamaService.logBuffer.drop(lastSize).also { lastSize = LlamaService.logBuffer.size }
   337→                    else emptyList()
   338→                }
   339→                if (lines.isNotEmpty()) {
   340→                    viewModelScope.launch(Dispatchers.Main) {
   341→                        lines.forEach { line ->
   342→                            liveLogs.add("[llama.cpp] $line")
   343→                            if (liveLogs.size > 1000) liveLogs.removeAt(0)
   344→                        }
   345→                    }
   346→                }
   347→                kotlinx.coroutines.delay(1000)
   348→            }
   349→        }
   350→    }
