   529→    /**
   530→     * Runs `ollama login`, captures the connect URL and opens the browser.
   531→     * The binary blocks until the user authorises on ollama.com, then stores
   532→     * credentials under $HOME/.ollama/ (HOME = context.filesDir).
   533→     */
   534→    fun triggerLogin(context: Context) {
   535→        if (!executor.isBinaryInstalled()) {
   536→            Toast.makeText(context, "Install binary first, then sign in.", Toast.LENGTH_LONG).show()
   537→            return
   538→        }
   539→        authLoginUrl    = null
   540→        isSigningIn     = true
   541→        cloudAuthStatus = ""
   542→        liveLogs.add("Starting Ollama login…")
   543→
   544→        viewModelScope.launch(Dispatchers.IO) {
   545→            var binarySupportsLogin = true
   546→
   547→            // ── Try the binary's built-in login first ──────────────────────────
   548→            val proc = executor.execLogin { line ->
   549→                viewModelScope.launch(Dispatchers.Main) {
   550→                    liveLogs.add(line)
   551→                    if (line.contains("unknown command", ignoreCase = true) ||
   552→                        (line.contains("Error", ignoreCase = true) && line.contains("login", ignoreCase = true))) {
   553→                        binarySupportsLogin = false
   554→                    }
   555→                    val match = "(https://ollama\\.com/connect\\S+)".toRegex().find(line)
   556→                    if (match != null) authLoginUrl = match.value
   557→                    if (line.contains("Logged in", ignoreCase = true) ||
   558→                        line.contains("Authenticated", ignoreCase = true)) {
   559→                        cloudAuthStatus = "✅ Logged in!"
   560→                        markLoggedIn()
   561→                    }
   562→                }
   563→            }
   564→            proc?.waitFor()
   565→
   566→            // Small delay for Main callbacks to finish
   567→            kotlinx.coroutines.delay(400)
   568→
   569→            withContext(Dispatchers.Main) {
   570→                when {
   571→                    // Binary produced the URL or already logged us in
   572→                    authLoginUrl != null || isLoggedIn -> {
   573→                        isSigningIn = false
   574→                    }
   575→                    // Binary doesn't support login → generate key pair ourselves
   576→                    !binarySupportsLogin || liveLogs.any { it.contains("unknown command", ignoreCase = true) } -> {
   577→                        liveLogs.add("Binary doesn't support 'login'. Generating auth key locally…")
   578→                        viewModelScope.launch(Dispatchers.IO) {
   579→                            try {
   580→                                val auth = OllamaAuth(context)
   581→                                val url  = auth.generateConnectUrl("devhive")
   582→                                withContext(Dispatchers.Main) {
   583→                                    authLoginUrl = url
   584→                                    isSigningIn  = false
   585→                                    liveLogs.add("✅ Auth key generated — open browser to authorize")
   586→                                }
   587→                            } catch (e: Exception) {
   588→                                withContext(Dispatchers.Main) {
   589→                                    cloudAuthStatus = "❌ Failed to generate key: ${e.message}"
   590→                                    isSigningIn     = false
   591→                                    liveLogs.add("❌ Key generation error: ${e.message}")
   592→                                }
   593→                            }
   594→                        }
   595→                    }
   596→                    // Binary exited cleanly — check for stored credentials
   597→                    else -> {
   598→                        isSigningIn = false
   599→                        readAndApplyStoredCredential()
   600→                    }
   601→                }
   602→            }
   603→        }
   604→    }
