  2612→// Render inline markdown (bold, italic, code, strikethrough) into AnnotatedString
  2613→fun inlineMd(raw: String): AnnotatedString = buildAnnotatedString {
  2614→    var i = 0
  2615→    while (i < raw.length) {
  2616→        when {
  2617→            // Bold **text** or __text__
  2618→            (raw.startsWith("**", i) || raw.startsWith("__", i)) -> {
  2619→                val marker = raw.substring(i, i + 2)
  2620→                val end = raw.indexOf(marker, i + 2)
  2621→                if (end != -1) {
  2622→                    pushStyle(SpanStyle(fontWeight = FontWeight.Bold))
  2623→                    append(raw.substring(i + 2, end))
  2624→                    pop(); i = end + 2
  2625→                } else { append(raw[i]); i++ }
  2626→            }
  2627→            // Italic *text* or _text_ (but not **)
  2628→            (raw.startsWith("*", i) && !raw.startsWith("**", i)) ||
  2629→            (raw.startsWith("_", i) && !raw.startsWith("__", i)) -> {
  2630→                val marker = raw[i].toString()
  2631→                val end = raw.indexOf(marker, i + 1)
  2632→                if (end != -1 && end > i + 1) {
  2633→                    pushStyle(SpanStyle(fontStyle = FontStyle.Italic))
  2634→                    append(raw.substring(i + 1, end))
  2635→                    pop(); i = end + 1
  2636→                } else { append(raw[i]); i++ }
  2637→            }
  2638→            // Inline code `code`
  2639→            raw.startsWith("`", i) -> {
  2640→                val end = raw.indexOf("`", i + 1)
  2641→                if (end != -1) {
  2642→                    pushStyle(SpanStyle(fontFamily = FontFamily.Monospace, background = Color(0xFF1A1A2E), color = Color(0xFF79C0FF)))
  2643→                    append(raw.substring(i + 1, end))
  2644→                    pop(); i = end + 1
  2645→                } else { append(raw[i]); i++ }
  2646→            }
  2647→            // Strikethrough ~~text~~
  2648→            raw.startsWith("~~", i) -> {
  2649→                val end = raw.indexOf("~~", i + 2)
  2650→                if (end != -1) {
  2651→                    pushStyle(SpanStyle(textDecoration = androidx.compose.ui.text.style.TextDecoration.LineThrough, color = Color(0xFF888888)))
  2652→                    append(raw.substring(i + 2, end))
  2653→                    pop(); i = end + 2
  2654→                } else { append(raw[i]); i++ }
  2655→            }
  2656→            else -> { append(raw[i]); i++ }
  2657→        }
  2658→    }
  2659→}
