  2661→fun parseMd(md: String): List<MdSegment> {
  2662→    val segs  = mutableListOf<MdSegment>()
  2663→    val lines = md.lines()
  2664→    var i     = 0
  2665→    while (i < lines.size) {
  2666→        val line = lines[i].trimEnd()
  2667→        when {
  2668→            // Code fences ``` or ~~~
  2669→            line.startsWith("```") || line.startsWith("~~~") -> {
  2670→                val fence = if (line.startsWith("```")) "```" else "~~~"
  2671→                val lang = line.drop(3).trim()
  2672→                val code = StringBuilder()
  2673→                i++
  2674→                while (i < lines.size && !lines[i].trimStart().startsWith(fence.take(3))) {
  2675→                    code.appendLine(lines[i]); i++
  2676→                }
  2677→                segs.add(MdSegment.MdCodeBlock(lang, code.toString().trimEnd()))
  2678→            }
  2679→            // Headings: # with or without trailing space
  2680→            line.matches(Regex("^#{1,6}( .*|$)")) -> {
  2681→                val lvl = line.takeWhile { it == '#' }.length
  2682→                segs.add(MdSegment.Heading(lvl, line.drop(lvl).trimStart()))
  2683→            }
  2684→            // Bullets
  2685→            line.matches(Regex("^\\s*[-*+] .*")) -> {
  2686→                val indent = line.length - line.trimStart().length
  2687→                segs.add(MdSegment.BulletItem(indent / 2, line.trimStart().drop(2)))
  2688→            }
  2689→            // Numbered list
  2690→            line.matches(Regex("^\\s*\\d+[.)].? .*")) -> {
  2691→                val num = line.trimStart().takeWhile { it.isDigit() }.toIntOrNull() ?: 1
  2692→                segs.add(MdSegment.NumberedItem(num, line.trimStart().dropWhile { it.isDigit() || it == '.' || it == ')' }.trimStart()))
  2693→            }
  2694→            // Blockquote > or >text
  2695→            line.startsWith(">") && line.length > 1 -> segs.add(MdSegment.Quote(line.drop(1).trimStart()))
  2696→            // Horizontal rule
  2697→            line.matches(Regex("^[-*_]{3,}\\s*$")) -> segs.add(MdSegment.Rule)
  2698→            line.isBlank() -> segs.add(MdSegment.Blank)
  2699→            else -> segs.add(MdSegment.Paragraph(line))
  2700→        }
  2701→        i++
  2702→    }
  2703→    return segs
  2704→}
