   368→                            }
   369→                        }
   370→                    }
   371→                }
   372→                // ── llama.cpp health (only while service is active) ──────────────────
   373→                if (llamaServiceActive || LlamaService.isRunning) {
   374→                    LlamaCppApi().checkHealth("http://127.0.0.1:$llamaPort") { ok, _ ->
