   401→            context.startForegroundService(Intent(context, OllamaService::class.java).apply {
   402→                putExtra("host", hostUrlState)
   403→                putExtra("origins", originsState)
   404→                // Pass API key so daemon can use OLLAMA_API_KEY for cloud models
   405→                if (cloudApiKey.isNotBlank()) putExtra("api_key", cloudApiKey)
   406→            })
   407→        }
   408→        viewModelScope.launch(Dispatchers.Main) {
   409→            delay(600)
   410→            refreshServiceStatus()
   411→        }
   412→    }
   413→
   414→    fun triggerBinaryInstall(context: Context) {
   415→        if (isInstalling) return
   416→        isInstalling = true
   417→        setupProgress = 0
   418→        setupStatus = "Starting download..."
   419→        viewModelScope.launch(Dispatchers.IO) {
   420→            val success = executor.downloadBinary(
   421→                url = downloadUrlState,
   422→                onProgress = { pct -> viewModelScope.launch(Dispatchers.Main) { setupProgress = pct } },
   423→                onLog = { msg -> viewModelScope.launch(Dispatchers.Main) { setupStatus = msg } }
   424→            )
   425→            withContext(Dispatchers.Main) {
   426→                isInstalling = false
   427→                val msg = if (success) "Binary installed successfully" else "Installation failed — see logs"
   428→                setupStatus = msg
   429→                checkBinaryInstalled()
   430→                Toast.makeText(context, msg, Toast.LENGTH_LONG).show()
   431→            }
   432→        }
   433→    }
   434→
   435→    // ── llama.cpp backend functions ───────────────────────────────────────────
   436→
   437→    fun toggleLlamaService(context: Context) {
   438→        if (LlamaService.isRunning) {
