   440→            llamaServiceActive = false
   441→            llamaApiOnline = false
   442→            llamaHealthStatus = ""
   443→        } else {
   444→            val model = llamaSelectedModel ?: run {
   445→                Toast.makeText(context, "Select a GGUF model first", Toast.LENGTH_SHORT).show()
   446→                return
   447→            }
   448→            context.startForegroundService(Intent(context, LlamaService::class.java).apply {
   449→                putExtra("model_path", model.absolutePath)
   450→                putExtra("host", "127.0.0.1")
   451→                putExtra("port", llamaPort)
   452→                putExtra("gpu_layers", llamaGpuLayers)
   453→                putExtra("ctx_size", llamaContextSize)
