                indicator = { tabPositions ->
                    Box(Modifier.tabIndicatorOffset(tabPositions[agentTab]).height(2.dp).background(OllamaGreen))
                }
            ) {
                listOf("Chat", "Files", "Steps").forEachIndexed { i, title ->
                    Tab(
