                        text = { Text(title, fontSize = 12.sp, color = if (agentTab == i) OllamaGreen else OllamaTextDim) }
                    )
                }
            }
        }

        when (agentTab) {
            0 -> AgentChatPane(vm, context, agentListState, focusManager)
            1 -> AgentFilesPane(vm, context)
            2 -> AgentStepsPane(vm)
        }
    }
