   777→    private fun sz(b: Long) = when {
   778→        b < 1024      -> "${b}B"
   779→        b < 1024*1024 -> "${b/1024}KB"
   780→        else          -> "%.1fMB".format(b/1024.0/1024.0)
   781→    }
