    36→sealed class ChatSegment {
    37→    data class PlainText(val text: String) : ChatSegment()
    38→    data class CodeBlock(val language: String, val code: String) : ChatSegment()
    39→}
    40→
    41→fun parseChatContent(content: String): List<ChatSegment> {
    42→    if (content.isBlank()) return listOf(ChatSegment.PlainText(content))
    43→    val result = mutableListOf<ChatSegment>()
    44→    val regex  = Regex("```(\\w*?)\\n([\\s\\S]*?)```|```([\\s\\S]*?)```")
    45→    var last   = 0
    46→    regex.findAll(content).forEach { m ->
    47→        val before = content.substring(last, m.range.first).trim()
    48→        if (before.isNotBlank()) result.add(ChatSegment.PlainText(before))
    49→        val lang = m.groupValues[1].trim()
    50→        val code = m.groupValues[2].ifBlank { m.groupValues[3] }.trimEnd()
    51→        result.add(ChatSegment.CodeBlock(lang, code))
    52→        last = m.range.last + 1
    53→    }
    54→    val tail = content.substring(last).trim()
    55→    if (tail.isNotBlank()) result.add(ChatSegment.PlainText(tail))
    56→    if (result.isEmpty()) result.add(ChatSegment.PlainText(content))
    57→    return result
    58→}
