    37→
    38→fun inlineMd(raw: String): AnnotatedString = buildAnnotatedString {
    39→    var i = 0
    40→    while (i < raw.length) {
    41→        when {
    42→            (raw.startsWith("**", i) || raw.startsWith("__", i)) -> {
    43→                val marker = raw.substring(i, i + 2)
    44→                val end = raw.indexOf(marker, i + 2)
    45→                if (end != -1) {
    46→                    pushStyle(SpanStyle(fontWeight = FontWeight.Bold))
    47→                    append(raw.substring(i + 2, end))
    48→                    pop(); i = end + 2
    49→                } else { append(raw[i]); i++ }
    50→            }
    51→            (raw.startsWith("*", i) && !raw.startsWith("**", i)) ||
    52→            (raw.startsWith("_", i) && !raw.startsWith("__", i)) -> {
    53→                val marker = raw[i].toString()
    54→                val end = raw.indexOf(marker, i + 1)
    55→                if (end != -1 && end > i + 1) {
    56→                    pushStyle(SpanStyle(fontStyle = FontStyle.Italic))
    57→                    append(raw.substring(i + 1, end))
    58→                    pop(); i = end + 1
    59→                } else { append(raw[i]); i++ }
    60→            }
    61→            raw.startsWith("`", i) -> {
    62→                val end = raw.indexOf("`", i + 1)
    63→                if (end != -1) {
    64→                    pushStyle(SpanStyle(fontFamily = FontFamily.Monospace, background = Color(0xFF1A1A2E), color = Color(0xFF79C0FF)))
    65→                    append(raw.substring(i + 1, end))
    66→                    pop(); i = end + 1
    67→                } else { append(raw[i]); i++ }
    68→            }
    69→            raw.startsWith("~~", i) -> {
    70→                val end = raw.indexOf("~~", i + 2)
    71→                if (end != -1) {
    72→                    pushStyle(SpanStyle(textDecoration = TextDecoration.LineThrough, color = Color(0xFF888888)))
    73→                    append(raw.substring(i + 2, end))
    74→                    pop(); i = end + 2
    75→                } else { append(raw[i]); i++ }
    76→            }
    77→            else -> { append(raw[i]); i++ }
    78→        }
    79→    }
    80→}
