    82→fun parseMd(md: String): List<MdSegment> {
    83→    val segs  = mutableListOf<MdSegment>()
    84→    val lines = md.lines()
    85→    var i     = 0
    86→    while (i < lines.size) {
    87→        val line = lines[i].trimEnd()
    88→        when {
    89→            line.startsWith("```") || line.startsWith("~~~") -> {
    90→                val fence = if (line.startsWith("```")) "```" else "~~~"
    91→                val lang  = line.drop(3).trim()
    92→                val code  = StringBuilder()
    93→                i++
    94→                while (i < lines.size && !lines[i].trimStart().startsWith(fence.take(3))) {
    95→                    code.appendLine(lines[i]); i++
    96→                }
    97→                segs.add(MdSegment.MdCodeBlock(lang, code.toString().trimEnd()))
    98→            }
    99→            line.matches(Regex("^#{1,6}( .*|$)")) -> {
   100→                val lvl = line.takeWhile { it == '#' }.length
   101→                segs.add(MdSegment.Heading(lvl, line.drop(lvl).trimStart()))
   102→            }
   103→            line.matches(Regex("^\\s*[-*+] .*")) -> {
   104→                val indent = line.length - line.trimStart().length
   105→                segs.add(MdSegment.BulletItem(indent / 2, line.trimStart().drop(2)))
   106→            }
   107→            line.matches(Regex("^\\s*\\d+[.)].? .*")) -> {
   108→                val num = line.trimStart().takeWhile { it.isDigit() }.toIntOrNull() ?: 1
   109→                segs.add(MdSegment.NumberedItem(num, line.trimStart().dropWhile { it.isDigit() || it == '.' || it == ')' }.trimStart()))
   110→            }
   111→            line.startsWith(">") && line.length > 1 -> segs.add(MdSegment.Quote(line.drop(1).trimStart()))
   112→            line.matches(Regex("^[-*_]{3,}\\s*$")) -> segs.add(MdSegment.Rule)
   113→            line.isBlank() -> segs.add(MdSegment.Blank)
   114→            else -> segs.add(MdSegment.Paragraph(line))
   115→        }
   116→        i++
   117→    }
   118→    return segs
   119→}
