   121→@Composable
   122→fun MarkdownViewer(markdown: String, modifier: Modifier = Modifier) {
   123→    val clipboard = LocalClipboardManager.current
   124→    val segments  = remember(markdown) { parseMd(markdown) }
   125→    val scrollState = rememberScrollState()
   126→    Column(
   127→        modifier.verticalScroll(scrollState).padding(horizontal = 14.dp, vertical = 10.dp),
   128→        verticalArrangement = Arrangement.spacedBy(3.dp)
   129→    ) {
   130→        segments.forEach { seg ->
   131→            when (seg) {
   132→                is MdSegment.Heading -> {
   133→                    if (seg.level == 1) Spacer(Modifier.height(8.dp))
   134→                    Text(
   135→                        seg.text, color = OllamaText,
   136→                        fontSize = when (seg.level) { 1 -> 22.sp; 2 -> 18.sp; 3 -> 15.sp; else -> 13.sp },
   137→                        fontWeight = if (seg.level <= 2) FontWeight.Bold else FontWeight.SemiBold,
   138→                        lineHeight = when (seg.level) { 1 -> 28.sp; 2 -> 24.sp; else -> 20.sp }
