   153→                    verticalAlignment = androidx.compose.ui.Alignment.Top
   154→                ) {
   155→                    Text("${seg.num}.", color = OllamaGreen, fontWeight = FontWeight.Bold, fontSize = 13.sp, modifier = Modifier.width(24.dp))
   156→                    Text(inlineMd(seg.text), color = OllamaText, fontSize = 13.sp, lineHeight = 20.sp, modifier = Modifier.weight(1f))
   157→                }
   158→                is MdSegment.MdCodeBlock -> {
   159→                    val code = seg.code
   160→                    Column(
   161→                        Modifier.fillMaxWidth().clip(RoundedCornerShape(8.dp))
   162→                            .background(Color(0xFF0D1117))
   163→                            .border(1.dp, Color(0xFF30363D), RoundedCornerShape(8.dp))
   164→                            .padding(10.dp)
   165→                    ) {
   166→                        Row(Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = androidx.compose.ui.Alignment.CenterVertically) {
   167→                            Text(seg.lang.ifBlank { "code" }, color = OllamaGreen, fontSize = 9.sp, fontWeight = FontWeight.Bold)
   168→                            TextButton(
   169→                                onClick = { clipboard.setText(AnnotatedString(code)) },
   170→                                contentPadding = PaddingValues(0.dp), modifier = Modifier.height(18.dp)
   171→                            ) { Text("copy", color = OllamaGreen, fontSize = 9.sp) }
   172→                        }
   173→                        Spacer(Modifier.height(4.dp))
   174→                        Text(code, color = Color(0xFF79C0FF), fontSize = 11.sp, fontFamily = FontFamily.Monospace)
   175→                    }
   176→                    Spacer(Modifier.height(2.dp))
   177→                }
   178→                is MdSegment.Quote -> Row(
   179→                    Modifier.fillMaxWidth().clip(RoundedCornerShape(4.dp))
   180→                        .background(Color(0xFF0A1A14))
   181→                        .padding(horizontal = 8.dp, vertical = 8.dp),
   182→                    verticalAlignment = androidx.compose.ui.Alignment.CenterVertically,
   183→                    horizontalArrangement = Arrangement.spacedBy(10.dp)
   184→                ) {
   185→                    Box(Modifier.width(3.dp).height(18.dp).background(OllamaGreen).clip(RoundedCornerShape(2.dp)))
   186→                    Text(seg.text, color = OllamaTextDim, fontSize = 13.sp, modifier = Modifier.weight(1f))
   187→                }
   188→                MdSegment.Rule  -> HorizontalDivider(color = OllamaBorder, modifier = Modifier.padding(vertical = 6.dp))
