   568→    // ─── Math evaluator (no eval — pure Kotlin) ───────────────────────────────
   569→
   570→    private fun evalExpr(e: String): String {
   571→        val r = evalMath(e.replace("\\s".toRegex(), "").replace("**", "^"))
   572→        return if (r == kotlin.math.floor(r) && !r.isInfinite()) r.toLong().toString()
   573→        else "%.10g".format(r).trimEnd('0').trimEnd('.')
   574→    }
   575→
   576→    private fun evalMath(raw: String): Double {
   577→        var e = raw
   578→
   579→        // Functions: sqrt, abs, floor, ceil, round
   580→        data class Fn(val name: String, val fn: (Double) -> Double)
   581→        val fns = listOf(
   582→            Fn("sqrt")  { v -> kotlin.math.sqrt(v) },
   583→            Fn("abs")   { v -> kotlin.math.abs(v)  },
   584→            Fn("floor") { v -> kotlin.math.floor(v) },
   585→            Fn("ceil")  { v -> kotlin.math.ceil(v)  },
   586→            Fn("round") { v -> kotlin.math.round(v).toDouble() }
   587→        )
   588→        for (fn in fns) {
   589→            val tag = "${fn.name}("
   590→            while (e.contains(tag)) {
   591→                val idx = e.indexOf(tag)
   592→                var d = 1; var j = idx + tag.length
   593→                while (j < e.length && d > 0) { if (e[j]=='(') d++ else if (e[j]==')') d--; j++ }
   594→                val inner = e.substring(idx + tag.length, j - 1)
   595→                e = e.substring(0, idx) + fn.fn(evalMath(inner)) + e.substring(j)
   596→            }
   597→        }
   598→
   599→        // Parentheses
   600→        while (e.contains('(')) {
   601→            val last  = e.lastIndexOf('(')
   602→            val close = e.indexOf(')', last)
   603→            if (close < 0) break
   604→            e = e.substring(0, last) + evalMath(e.substring(last+1, close)) + e.substring(close+1)
   605→        }
   606→
   607→        // Tokenise into numbers + operators
   608→        val nums = mutableListOf<Double>()
   609→        val ops  = mutableListOf<Char>()
   610→        var i = 0
   611→        while (i < e.length) {
   612→            val c = e[i]
   613→            if (c.isDigit() || c == '.' ||
   614→                (c == '-' && (i == 0 || e[i-1] in "+-*/^%"))) {
   615→                var j = i + 1
   616→                while (j < e.length && (e[j].isDigit() || e[j] == '.')) j++
   617→                nums.add(e.substring(i, j).toDouble()); i = j
   618→            } else if (c in "+-*/^%") { ops.add(c); i++ }
   619→            else i++
   620→        }
   621→        if (nums.isEmpty()) return e.toDoubleOrNull() ?: throw IllegalArgumentException("Cannot parse: $e")
   622→
   623→        // Precedence: ^ first, then * / %, then + -
   624→        var oi = ops.indexOf('^')
   625→        while (oi >= 0) {
   626→            nums[oi] = Math.pow(nums[oi], nums[oi+1])
   627→            nums.removeAt(oi+1); ops.removeAt(oi); oi = ops.indexOf('^')
   628→        }
   629→        oi = ops.indexOfFirst { it in "*/%" }
   630→        while (oi >= 0) {
   631→            nums[oi] = when (ops[oi]) { '*' -> nums[oi]*nums[oi+1]; '/' -> nums[oi]/nums[oi+1]; else -> nums[oi]%nums[oi+1] }
   632→            nums.removeAt(oi+1); ops.removeAt(oi)
   633→            oi = ops.indexOfFirst { it in "*/%" }
   634→        }
   635→        var r = nums[0]
   636→        ops.forEachIndexed { k, op -> r = if (op == '+') r + nums[k+1] else r - nums[k+1] }
   637→        return r
   638→    }
