   640→    // ─── Agent loop ───────────────────────────────────────────────────────────
   641→
   642→    private var askUserFn: (suspend (String) -> String)? = null
   643→
   644→    suspend fun runAgentLoop(
   645→        userTask: String,
   646→        model: String,
   647→        baseUrl: String,
   648→        maxSteps: Int = 25,
   649→        cloudApiKey: String = "",
   650→        backend: String = "ollama",
   651→        onAskUser: (suspend (String) -> String)? = null,
   652→        onStep: suspend (AgentStep) -> Unit
   653→    ) {
   654→        askUserFn = onAskUser
   655→
   656→        // Always start fresh — clearing the chat truly clears context
   657→        val messages = mutableListOf(
   658→            ChatMessage("system", systemPrompt()),
   659→            ChatMessage("user",   userTask)
   660→        )
   661→
   662→        val api   = OllamaApi()
   663→        val cloud = model.endsWith(":cloud")
   664→        var steps = 0
   665→        var errs  = 0
   666→
   667→        while (steps < maxSteps) {
   668→            steps++
   669→            var response = ""
   670→            var streamOk = true
   671→            var streamErr = ""
   672→
   673→            try {
   674→                suspendCancellableCoroutine<Unit> { cont ->
   675→                    val onTok: (String) -> Unit = { response += it }
   676→                    val onDone: (Boolean, String) -> Unit = { s, m ->
   677→                        if (!s) { streamOk = false; streamErr = m }
   678→                        if (!cont.isCompleted) cont.resume(Unit)
   679→                    }
   680→                    val call = when {
   681→                        cloud && cloudApiKey.isNotBlank() ->
   682→                            api.cloudChatStream(cloudApiKey, model, messages,
   683→                                onTokenGenerated = onTok, onComplete = onDone)
   684→                        backend == "llamacpp" ->
   685→                            LlamaCppApi().chatStream(baseUrl, messages,
   686→                                onToken = onTok, onComplete = onDone)
   687→                        else ->
   688→                            api.chatStream(baseUrl, model, messages,
   689→                                onTokenGenerated = onTok, onComplete = onDone)
   690→                    }
   691→                    cont.invokeOnCancellation { call.cancel() }
   692→                }
   693→            } catch (ex: kotlinx.coroutines.CancellationException) { throw ex }
   694→            catch (ex: Exception) {
   695→                onStep(AgentStep("error", "❌ LLM error: ${ex.message}", true)); break
   696→            }
   697→
   698→            if (!streamOk) {
   699→                errs++
   700→                onStep(AgentStep("error", "❌ $streamErr", true))
   701→                if (errs >= 3) { onStep(AgentStep("info", "⚠️ Too many errors — is Ollama running?")); break }
   702→                kotlinx.coroutines.delay(1000); continue
   703→            }
   704→            if (response.isBlank()) {
   705→                errs++
   706→                onStep(AgentStep("error", "❌ Model returned empty response.", true))
   707→                if (errs >= 3) break
   708→                kotlinx.coroutines.delay(800); continue
   709→            }
   710→            errs = 0
   711→
   712→            // Parse
   713→            val toolCalls = parseToolCalls(response)
   714→
   715→            // Show non-tool text (strip all known tool block formats)
   716→            val display = response
   717→                .replace(Regex("""WRITE_FILE>>[^\n]+\n[\s\S]*?<<WRITE_FILE"""), "")
   718→                .replace(Regex("""TOOL>>\s*\n[\s\S]*?\n?<<TOOL"""), "")
   719→                .replace(Regex("""```tool\s*\n[\s\S]*?\n?```"""), "")
   720→                .replace(Regex("""```json\s*\n[\s\S]*?\n?```"""), "")
   721→                .trim()
   722→            if (display.isNotBlank()) onStep(AgentStep("assistant", display))
   723→
   724→            // No tool found — nudge model (max 2 nudges before giving up)
   725→            if (toolCalls.isEmpty()) {
   726→                messages.add(ChatMessage("assistant", response))
   727→                val nudges = messages.count { it.role == "user" && it.content.startsWith("[NUDGE]") }
   728→                if (nudges < 2) {
   729→                    messages.add(ChatMessage("user",
   730→                        "[NUDGE] You must output a tool call. Examples:\n" +
   731→                        "TOOL>>\n{\"name\":\"list_dir\",\"path\":\"$workingDir\"}\n<<TOOL\n\n" +
   732→                        "Or to finish:\nTOOL>>\n{\"name\":\"complete\",\"summary\":\"what was done\"}\n<<TOOL"
   733→                    ))
   734→                    continue
   735→                }
   736→                break
   737→            }
   738→
   739→            // Execute tools
   740→            val resultBuf = StringBuilder()
   741→            var done = false
   742→            for (call in toolCalls) {
   743→                val toolName = call.optString("name", "?")
   744→                onStep(AgentStep("tool_call", "🔧 $toolName"))
   745→                val result = executeTool(call)
   746→                onStep(result)
   747→                resultBuf.appendLine(result.content).appendLine("---")
   748→                if (result.type == "complete") { done = true; break }
   749→            }
   750→
   751→            messages.add(ChatMessage("assistant", response))
   752→            if (done) break
   753→
   754→            messages.add(ChatMessage("user",
   755→                "Tool results:\n$resultBuf\nProceed. Output the next TOOL>> or WRITE_FILE>> block."))
   756→
   757→            // Trim context window: keep system + original task + last 12 turns
   758→            if (messages.size > 30) {
   759→                val head = messages.take(2)
   760→                val tail = messages.takeLast(12)
   761→                messages.clear()
   762→                messages.addAll(head)
   763→                messages.add(ChatMessage("system", "[Earlier steps trimmed — context management]"))
   764→                messages.addAll(tail)
   765→            }
   766→        }
   767→
   768→        if (steps >= maxSteps)
   769→            onStep(AgentStep("info", "⚠️ Max steps ($maxSteps) reached. Task may be incomplete."))
   770→    }
   771→
   772→    // ─── Helpers ──────────────────────────────────────────────────────────────
   773→
   774→    private fun ok(msg: String)  = AgentStep("tool_result", msg, isError = false)
   775→    private fun err(msg: String) = AgentStep("tool_result", "❌ $msg", isError = true)
