    27→sealed class MdSegment {
    28→    data class Heading(val level: Int, val text: String) : MdSegment()
    29→    data class Paragraph(val text: String) : MdSegment()
    30→    data class BulletItem(val indent: Int, val text: String) : MdSegment()
    31→    data class NumberedItem(val num: Int, val text: String) : MdSegment()
    32→    data class MdCodeBlock(val lang: String, val code: String) : MdSegment()
