    37→
    38→fun inlineMd(raw: String): AnnotatedString = buildAnnotatedString {
    39→    var i = 0
    40→    while (i < raw.length) {
    41→        when {
    42→            (raw.startsWith("**", i) || raw.startsWith("__", i)) -> {
    43→                val marker = raw.substring(i, i + 2)
    44→                val end = raw.indexOf(marker, i + 2)
    45→                if (end != -1) {
    46→                    pushStyle(SpanStyle(fontWeight = FontWeight.Bold))
    47→                    append(raw.substring(i + 2, end))
    48→                    pop(); i = end + 2
    49→                } else { append(raw[i]); i++ }
    50→            }
    51→            (raw.startsWith("*", i) && !raw.startsWith("**", i)) ||
    52→            (raw.startsWith("_", i) && !raw.startsWith("__", i)) -> {
    53→                val marker = raw[i].toString()
    54→                val end = raw.indexOf(marker, i + 1)
    55→                if (end != -1 && end > i + 1) {
    56→                    pushStyle(SpanStyle(fontStyle = FontStyle.Italic))
    57→                    append(raw.substring(i + 1, end))
    58→                    pop(); i = end + 1
    59→                } else { append(raw[i]); i++ }
    60→            }
    61→            raw.startsWith("`", i) -> {
    62→                val end = raw.indexOf("`", i + 1)
    63→                if (end != -1) {
    64→                    pushStyle(SpanStyle(fontFamily = FontFamily.Monospace, background = Color(0xFF1A1A2E), color = Color(0xFF79C0FF)))
    65→                    append(raw.substring(i + 1, end))
    66→                    pop(); i = end + 1
    67→                } else { append(raw[i]); i++ }
    68→            }
    69→            raw.startsWith("~~", i) -> {
    70→                val end = raw.indexOf("~~", i + 2)
    71→                if (end != -1) {
    72→                    pushStyle(SpanStyle(textDecoration = TextDecoration.LineThrough, color = Color(0xFF888888)))
    73→                    append(raw.substring(i + 2, end))
    74→                    pop(); i = end + 2
    75→                } else { append(raw[i]); i++ }
    76→            }
    77→            else -> { append(raw[i]); i++ }
    78→        }
    79→    }
    80→}
    81→
    82→fun parseMd(md: String): List<MdSegment> {
    83→    val segs  = mutableListOf<MdSegment>()
    84→    val lines = md.lines()
    85→    var i     = 0
    86→    while (i < lines.size) {
    87→        val line = lines[i].trimEnd()
    88→        when {
    89→            line.startsWith("```") || line.startsWith("~~~") -> {
    90→                val fence = if (line.startsWith("```")) "```" else "~~~"
    91→                val lang  = line.drop(3).trim()
    92→                val code  = StringBuilder()
    93→                i++
    94→                while (i < lines.size && !lines[i].trimStart().startsWith(fence.take(3))) {
    95→                    code.appendLine(lines[i]); i++
    96→                }
    97→                segs.add(MdSegment.MdCodeBlock(lang, code.toString().trimEnd()))
    98→            }
    99→            line.matches(Regex("^#{1,6}( .*|$)")) -> {
   100→                val lvl = line.takeWhile { it == '#' }.length
   101→                segs.add(MdSegment.Heading(lvl, line.drop(lvl).trimStart()))
   102→            }
   103→            line.matches(Regex("^\\s*[-*+] .*")) -> {
   104→                val indent = line.length - line.trimStart().length
   105→                segs.add(MdSegment.BulletItem(indent / 2, line.trimStart().drop(2)))
   106→            }
   107→            line.matches(Regex("^\\s*\\d+[.)].? .*")) -> {
   108→                val num = line.trimStart().takeWhile { it.isDigit() }.toIntOrNull() ?: 1
   109→                segs.add(MdSegment.NumberedItem(num, line.trimStart().dropWhile { it.isDigit() || it == '.' || it == ')' }.trimStart()))
   110→            }
   111→            line.startsWith(">") && line.length > 1 -> segs.add(MdSegment.Quote(line.drop(1).trimStart()))
   112→            line.matches(Regex("^[-*_]{3,}\\s*$")) -> segs.add(MdSegment.Rule)
   113→            line.isBlank() -> segs.add(MdSegment.Blank)
   114→            else -> segs.add(MdSegment.Paragraph(line))
   115→        }
   116→        i++
   117→    }
   118→    return segs
   119→}
