   122→fun MarkdownViewer(markdown: String, modifier: Modifier = Modifier) {
   123→    val clipboard = LocalClipboardManager.current
   124→    val segments  = remember(markdown) { parseMd(markdown) }
   125→    val scrollState = rememberScrollState()
