   316→    fun toggleLlamaService(context: Context) {
   317→        if (LlamaService.isRunning) {
   318→            context.stopService(Intent(context, LlamaService::class.java))
   319→            llamaServiceActive = false; llamaApiOnline = false; llamaHealthStatus = ""
   320→        } else {
   321→            val model = llamaSelectedModel ?: run {
   322→                Toast.makeText(context, "Select a GGUF model first", Toast.LENGTH_SHORT).show()
   323→                return
   324→            }
   325→            context.startForegroundService(Intent(context, LlamaService::class.java).apply {
   326→                putExtra("model_path", model.absolutePath)
   327→                putExtra("host", "127.0.0.1")
   328→                putExtra("port", llamaPort)
   329→                putExtra("gpu_layers", llamaGpuLayers)
   330→                putExtra("ctx_size", llamaContextSize)
   331→                putExtra("threads", llamaThreads)
   332→                putExtra("batch_size", llamaBatchSize)
   333→            })
   334→            llamaServiceActive = true; llamaHealthStatus = "⏳ Starting server…"
   335→            viewModelScope.launch(Dispatchers.IO) {
   336→                repeat(30) { attempt ->
   337→                    delay(1000)
   338→                    if (!LlamaService.isRunning) {
   339→                        viewModelScope.launch(Dispatchers.Main) {
   340→                            llamaServiceActive = false; llamaApiOnline = false
   341→                            llamaHealthStatus = "❌ Server process exited — check Logs for details"
   342→                        }
   343→                        return@launch
   344→                    }
   345→                    LlamaCppApi().checkHealth("http://127.0.0.1:$llamaPort") { ok, msg ->
   346→                        viewModelScope.launch(Dispatchers.Main) {
   347→                            if (ok) { llamaApiOnline = true; llamaHealthStatus = "✅ Server running on port $llamaPort" }
   348→                            else if (attempt == 29) { llamaHealthStatus = "❌ Timeout — $msg" }
   349→                        }
   350→                    }
   351→                    if (llamaApiOnline) return@launch
   352→                }
   353→            }
   354→        }
   355→    }
