   393→    fun triggerLogin(context: Context) {
   394→        if (!executor.isBinaryInstalled()) {
   395→            Toast.makeText(context, "Install binary first, then sign in.", Toast.LENGTH_LONG).show()
   396→            return
   397→        }
   398→        authLoginUrl = null; isSigningIn = true; cloudAuthStatus = ""
   399→        liveLogs.add("Starting Ollama login…")
   400→        viewModelScope.launch(Dispatchers.IO) {
   401→            var binarySupportsLogin = true
   402→            val proc = executor.execLogin { line ->
   403→                viewModelScope.launch(Dispatchers.Main) {
   404→                    liveLogs.add(line)
   405→                    if (line.contains("unknown command", ignoreCase = true) ||
   406→                        (line.contains("Error", ignoreCase = true) && line.contains("login", ignoreCase = true)))
   407→                        binarySupportsLogin = false
   408→                    val match = "(https://ollama\\.com/connect\\S+)".toRegex().find(line)
   409→                    if (match != null) authLoginUrl = match.value
   410→                    if (line.contains("Logged in", ignoreCase = true) || line.contains("Authenticated", ignoreCase = true)) {
   411→                        cloudAuthStatus = "✅ Logged in!"; markLoggedIn()
   412→                    }
   413→                }
   414→            }
   415→            proc?.waitFor()
   416→            kotlinx.coroutines.delay(400)
   417→            withContext(Dispatchers.Main) {
   418→                when {
   419→                    authLoginUrl != null || isLoggedIn -> isSigningIn = false
   420→                    !binarySupportsLogin || liveLogs.any { it.contains("unknown command", ignoreCase = true) } -> {
   421→                        liveLogs.add("Binary doesn't support 'login'. Generating auth key locally…")
   422→                        viewModelScope.launch(Dispatchers.IO) {
   423→                            try {
   424→                                val auth = OllamaAuth(context)
   425→                                val url  = auth.generateConnectUrl("devhive")
   426→                                withContext(Dispatchers.Main) {
   427→                                    authLoginUrl = url; isSigningIn = false
   428→                                    liveLogs.add("✅ Auth key generated — open browser to authorize")
   429→                                }
   430→                            } catch (e: Exception) {
   431→                                withContext(Dispatchers.Main) {
   432→                                    cloudAuthStatus = "❌ Failed to generate key: ${e.message}"
   433→                                    isSigningIn = false; liveLogs.add("❌ Key generation error: ${e.message}")
   434→                                }
   435→                            }
   436→                        }
   437→                    }
   438→                    else -> { isSigningIn = false; readAndApplyStoredCredential() }
   439→                }
   440→            }
   441→        }
   442→    }
