   447→            withContext(Dispatchers.Main) {
   448→                if (!credential.isNullOrBlank()) {
   449→                    persistApiKey(credential)
   450→                    cloudAuthStatus = "✅ Credentials found and saved!"
   451→                    liveLogs.add("✅ Credentials stored — cloud auth active.")
   452→                }
   453→            }
   454→        }
   455→    }
