   457→    fun validateAndSaveApiKey(context: Context, key: String) {
   458→        val trimmed = key.trim()
   459→        if (trimmed.isBlank()) { Toast.makeText(context, "Enter an API key first.", Toast.LENGTH_SHORT).show(); return }
   460→        isValidatingKey = true; cloudAuthStatus = "Validating key…"
   461→        api.validateCloudApiKey(trimmed) { ok, msg ->
   462→            viewModelScope.launch(Dispatchers.Main) {
   463→                isValidatingKey = false
   464→                if (ok) {
   465→                    persistApiKey(trimmed); manualApiKeyInput = ""
   466→                    cloudAuthStatus = "✅ Key validated and saved!"
   467→                    Toast.makeText(context, "API key saved — cloud auth active.", Toast.LENGTH_SHORT).show()
   468→                } else {
   469→                    cloudAuthStatus = "❌ $msg"
   470→                    Toast.makeText(context, "Validation failed: $msg", Toast.LENGTH_LONG).show()
   471→                }
   472→            }
   473→        }
   474→    }
